import React from "react";
import "./ProductCard.css";

const badgeLabels = {
  hit: "Hit",
  new: "New",
  sale: "Sale",
};

const ProductCard = ({
  id,
  title,
  price,
  oldPrice,
  currency = "₴",
  image,
  rating,
  inStock,
  discount,
  badges = [],
  onAddToCart,
}) => {
  const safeRating =
    typeof rating === "number" ? Math.min(5, Math.max(0, Math.round(rating))) : null;
  const stars =
    safeRating === null ? null : "★".repeat(safeRating) + "☆".repeat(5 - safeRating);
  const hasSalePrice = oldPrice || discount;
  const visibleBadges = [...badges];

  if (discount && !visibleBadges.includes("sale")) {
    visibleBadges.push("sale");
  }

  const handleAddToCart = () => {
    if (inStock && onAddToCart) {
      onAddToCart(id);
    }
  };

  return (
    <article className="product-card">
      <div className="product-card__image-wrap">
        <img className="product-card__image" src={image} alt={title} />

        {visibleBadges.length > 0 && (
          <div className="product-card__badges">
            {visibleBadges.map((badge) => (
              <span className={`product-card__badge product-card__badge--${badge}`} key={badge}>
                {badge === "sale" && discount ? `-${discount}%` : badgeLabels[badge] || badge}
              </span>
            ))}
          </div>
        )}
      </div>

      <div className="product-card__content">
        <h3 className="product-card__title">{title}</h3>

        {stars && <div className="product-card__rating">{stars}</div>}

        <div className="product-card__prices">
          {hasSalePrice && oldPrice && (
            <span className="product-card__old-price">
              {oldPrice}
              {currency}
            </span>
          )}

          <span className={hasSalePrice ? "product-card__price product-card__price--sale" : "product-card__price"}>
            {price}
            {currency}
          </span>
        </div>

        <button
          className="product-card__button"
          type="button"
          disabled={!inStock}
          onClick={handleAddToCart}
        >
          {inStock ? "В кошик" : "Немає в наявності"}
        </button>
      </div>
    </article>
  );
};

export default ProductCard;
